import { Wrench, Cpu, Settings2, HardDrive, Zap, LockKeyhole,Shield, Database, Briefcase, Headset, MonitorSpeaker } from 'lucide-react';

export const servicesData = [
// Categoria 1: Limpeza e Manutenção
  {
    icon: Wrench,
    price: '80',
    title: 'Limpeza Física Completa',
    description: 'Remoção total de poeira interna e externa, limpeza de coolers, ventoinhas e componentes para máxima eficiência de resfriamento.',
  },
  {
    icon: Cpu,
    price: '60',
    title: 'Troca de Pasta Térmica Premium',
    description: 'Aplicação de pasta térmica de alta qualidade para otimizar a transferência de calor e reduzir temperaturas do processador.',
  },
  {
    icon: Settings2,
    price: '120',
    title: 'Manutenção Completa',
    description: 'Limpeza física + troca de pasta térmica + verificação de componentes. Pacote completo para renovação total.',
  },
// Categoria 2: Sistema e Performance
  {
    icon: MonitorSpeaker,
    price: '150',
    title: 'Formatação + Otmização Windows',
    description: 'Reinstalação limpa do sistema operacional, drivers atualizados e configurações otimizadas para máxima performance.',
  },
  {
    icon: HardDrive,
    price: '100',
    title: 'Instalação de SSD',
    description: 'Migração completa do sistema para SSD, incluindo clonagem de dados e configuraçãoes para inicialização ultra-rápida',
  },
  {
    icon: Zap,
    price: '50',
    title: 'Upfrade de Memória RAM',
    description: 'Instalação e configuração de memória RAM adicional para melhorar multitasking e performance geral do sistema.',
  },
// Categoria 3: Recuperação e Backup
  {
    icon: Shield,
    price: '200',
    title: 'Recuperação de Dados',
    description: 'Recuperação profissional de arquivos perdidos em HDs, SSDs, pendrives e cartões de memória com tecnologia avançada.'
  },
  {
    icon: Database,
    price: '80',
    title: 'Backup Completo',
    description: 'Criação de backup seguro de todos os seus dados importantes com configuração de backup automático.',
  },
];
